const parts = msg.topic.split('/');
const bikeId = parts[1];
const d = msg.payload;

msg.payload = [{
    measurement: 'bike',
    tags: { id: bikeId },
    fields: {
        lat: d.position.lat,
        lng: d.position.lng,
        current_speed: d.current_speed,
        imu_x: d.imu.x,
        imu_y: d.imu.y,
        imu_z: d.imu.z,
        imu_dx: d.imu.dx,
        imu_dy: d.imu.dy,
        imu_dz: d.imu.dz,
        battery: d.battery,
        locked: d.locked,
        status: d.status,
        current_ride: d.current_ride || ''
    }
}];

const lastSeen = global.get('bikeLastSeen') || {};
lastSeen[bikeId] = Date.now();
global.set('bikeLastSeen', lastSeen);

return msg;

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

const z = data.imu.z;
const x = data.imu.x;
const y = data.imu.y;
const totalAcc = Math.sqrt(x * x + y * y + z * z);
const tiltFromGravity = Math.abs(z - 9.8);
const isFall = tiltFromGravity > 4.0 || totalAcc > 25;

if (isFall && data.status === 'rented') {
    const activeAlerts = flow.get('activeFallAlerts') || {};
    if (activeAlerts[bikeId]) return null;
    activeAlerts[bikeId] = Date.now();
    flow.set('activeFallAlerts', activeAlerts);
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'fall',
            severity: 'high'
        },
        fields: {
            alert_id: 'fall-' + bikeId + '-' + ts,
            message: 'Fall detected: tilt=' + tiltFromGravity.toFixed(1) + ', total_acc=' + totalAcc.toFixed(2) + ' m/s2'
        }
    }];
    return msg;
} else if (!isFall) {
    const activeAlerts = flow.get('activeFallAlerts') || {};
    if (activeAlerts[bikeId]) {
        delete activeAlerts[bikeId];
        flow.set('activeFallAlerts', activeAlerts);
    }
}

return null;

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

const ZONES = global.get('parkingZones') || [];
if (ZONES.length === 0) {
    node.warn('No parking zones loaded');
    return null;
}

function distanceMeters(lat1, lng1, lat2, lng2) {
    const R = 6371000;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLng/2) * Math.sin(dLng/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

if (!data.locked) {
    const activeAlerts = flow.get('activeParkingAlerts') || {};
    if (activeAlerts[bikeId]) {
        delete activeAlerts[bikeId];
        flow.set('activeParkingAlerts', activeAlerts);
    }
    return null;
}

const lat = data.position.lat;
const lng = data.position.lng;

const insideZone = ZONES.some(zone => {
    const dist = distanceMeters(lat, lng, zone.center.lat, zone.center.lng);
    return dist <= zone.radius;
});

if (!insideZone) {
    const activeAlerts = flow.get('activeParkingAlerts') || {};
    if (activeAlerts[bikeId]) return null;
    activeAlerts[bikeId] = Date.now();
    flow.set('activeParkingAlerts', activeAlerts);
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'parking_violation',
            severity: 'medium'
        },
        fields: {
            alert_id: 'parking_violation-' + bikeId + '-' + ts,
            message: 'Bike parked outside authorized zone at ' + lat.toFixed(5) + ', ' + lng.toFixed(5)
        }
    }];
    return msg;
} else {
    const activeAlerts = flow.get('activeParkingAlerts') || {};
    if (activeAlerts[bikeId]) {
        delete activeAlerts[bikeId];
        flow.set('activeParkingAlerts', activeAlerts);
    }
}

return null;

const fs = global.get('fs');
const path = '/shared/parking-zones.json';

try {
    const raw = fs.readFileSync(path, 'utf8');
    const config = JSON.parse(raw);
    global.set('parkingZones', config.zones);
    node.log('Loaded ' + config.zones.length + ' parking zones for ' + config.city);
    msg.payload = config;
    return msg;
} catch (e) {
    node.error('Failed to load parking zones: ' + e.message);
    return null;
}

const data = msg.payload;
const parts = msg.topic.split('/');
const bikeId = parts[1];

let severity = null;
if (data.battery <= 0) {
    severity = 'high';
} else if (data.battery <= 5) {
    severity = 'medium';
} else if (data.battery <= 15) {
    severity = 'low';
}

if (severity) {
    const activeBatteryAlerts = flow.get('activeBatteryAlerts') || {};
    const existing = activeBatteryAlerts[bikeId];
    if (existing && existing === severity) return null;
    activeBatteryAlerts[bikeId] = severity;
    flow.set('activeBatteryAlerts', activeBatteryAlerts);
    const ts = Date.now();
    msg.payload = [{
        measurement: 'alert',
        tags: {
            bike_id: bikeId,
            type: 'low_battery',
            severity: severity
        },
        fields: {
            alert_id: 'low_battery-' + bikeId + '-' + ts,
            message: 'Battery low: ' + data.battery.toFixed(1) + '% (severity: ' + severity + ')'
        }
    }];
    return msg;
} else {
    const activeBatteryAlerts = flow.get('activeBatteryAlerts') || {};
    if (activeBatteryAlerts[bikeId]) {
        delete activeBatteryAlerts[bikeId];
        flow.set('activeBatteryAlerts', activeBatteryAlerts);
    }
}

return null;

const lastSeen = global.get('bikeLastSeen') || {};
const activeAlerts = flow.get('activeConnectivityAlerts') || {};
const now = Date.now();
const TIMEOUT_MS = 60000;
const alerts = [];

for (const bikeId of Object.keys(lastSeen)) {
    const elapsed = now - lastSeen[bikeId];
    if (elapsed > TIMEOUT_MS) {
        if (activeAlerts[bikeId]) continue;
        activeAlerts[bikeId] = now;
        alerts.push({
            measurement: 'alert',
            tags: {
                bike_id: bikeId,
                type: 'connectivity',
                severity: 'medium'
            },
            fields: {
                alert_id: 'connectivity-' + bikeId + '-' + now,
                message: 'Bike offline: no data received for ' + Math.round(elapsed / 1000) + 's'
            }
        });
    } else if (activeAlerts[bikeId]) {
        delete activeAlerts[bikeId];
    }
}

flow.set('activeConnectivityAlerts', activeAlerts);

if (alerts.length > 0) {
    msg.payload = alerts;
    return msg;
}

return null;
